package be.schaubroeck.lpb.rkm.rekenmotor.service.web;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenActionType;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenActionFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenActionService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenUitAgendaService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenUitArtikelAgendaService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenUitBerekendenService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenViaBoekDatumService;
import be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding.RekenUitVoorbereidingService;
import be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding.RekenUitVoorbereidingService2;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.PersoonService;
import org.springframework.beans.factory.annotation.Autowired;

public class RekenActionFactoryImp implements RekenActionFactory {

    @Autowired
    private RekenUitAgendaService rekenUitAgendaService;

    @Autowired
    private RekenUitVoorbereidingService rekenUitVoorbereidingService;

    @Autowired
    private RekenUitVoorbereidingService2 rekenUitVoorbereidingService2;

    @Autowired
    private RekenUitBerekendenService rekenUitBerekendenService;

    @Autowired
    private RekenViaBoekDatumService rekenViaBoekDatumService;

    @Autowired
    private RekenUitArtikelAgendaService rekenUitArtikelAgendaService;

    @Autowired
    private PersoonService persoonService;

    @Override
    public RekenActionService bepaal(RekenActionType type) {
        RekenActionService actionService;
        switch (type) {
            case REKEN_UIT_REKENAGENDA:
                actionService = rekenUitAgendaService;
                break;
            case REKEN_UIT_VOORBEREIDING:
                actionService = rekenUitVoorbereidingService;
                break;
            case REKEN_UIT_VOORBEREIDING2:
                actionService = rekenUitVoorbereidingService2;
                break;
            case HERREKEN_ALLE_BEREKENDEN:
                actionService = rekenUitBerekendenService;
                break;
            case REKEN_UIT_ARTIKELAGENDA:
                actionService = rekenUitArtikelAgendaService;
                break;
            case HERREKEN_VIA_BOEKDATUM:
                actionService = rekenViaBoekDatumService;
                break;
            default:
                throw new MessageException("Onbekende RekenActionType");
        }
        return actionService;
    }

    @Override
    public PersoonService getPersoonService() {
        return persoonService;
    }
}
